const data = $input.first().json;

// Workflow info
const workflowName  = data?.workflow?.name              || 'Unknown Workflow';
const workflowId    = data?.workflow?.id                || 'N/A';
const executionId   = data?.execution?.id               || 'N/A';
const executionMode = data?.execution?.mode             || 'N/A';
const startedAt     = data?.execution?.startedAt        || 'N/A';
const lastNode      = data?.execution?.lastNodeExecuted || 'N/A';

// Build URLs manually
const n8nBaseUrl   = 'https://abobby.app.n8n.cloud';
const workflowUrl  = workflowId  !== 'N/A' ? `${n8nBaseUrl}/workflow/${workflowId}` : '#';
const executionUrl = executionId !== 'N/A' ? `${n8nBaseUrl}/workflow/${workflowId}/executions/${executionId}` : '#';

// Basic error info
const errorMessage = data?.execution?.error?.message ||
                     data?.error?.message             ||
                     'No error message';

const errorName    = data?.execution?.error?.name    ||
                     data?.error?.name                ||
                     'Unknown Error';

const stackTrace   = data?.execution?.error?.stack   ||
                     data?.error?.stack               ||
                     'No stack trace';

// Capture deeper error details
const errorCause =
  data?.execution?.error?.cause?.message     ||
  data?.execution?.error?.cause?.description ||
  data?.execution?.error?.description        ||
  data?.error?.cause?.message                ||
  data?.error?.cause?.description            ||
  data?.error?.description                   ||
  '';

// Capture HTTP status if any
const httpStatus =
  data?.execution?.error?.cause?.response?.status ||
  data?.execution?.error?.httpCode               ||
  data?.error?.httpCode                          ||
  '';

// Capture API response body
const apiResponseBody =
  data?.execution?.error?.cause?.response?.body ||
  data?.execution?.error?.cause?.body           ||
  data?.error?.cause?.response?.body            ||
  data?.error?.cause?.body                      ||
  '';

// Build full error message
let fullErrorMessage = errorMessage;
if (errorCause) fullErrorMessage += `\n📎 Cause: ${errorCause}`;
if (httpStatus) fullErrorMessage += `\n🔢 HTTP Status: ${httpStatus}`;
if (apiResponseBody) {
  const bodyText = typeof apiResponseBody === 'object'
    ? JSON.stringify(apiResponseBody, null, 2)
    : apiResponseBody;
  fullErrorMessage += `\n📄 API Response: ${bodyText}`;
}

// Time
const timestamp    = new Date().toISOString();
const readableTime = new Date().toLocaleString('en-IN', {
  timeZone: 'Asia/Kolkata',
  dateStyle: 'full',
  timeStyle: 'long'
});

// Email HTML
const emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; background: #f4f4f4; margin: 0; padding: 20px; }
    .container { background: #ffffff; border-radius: 8px; padding: 30px; max-width: 700px; margin: auto; border-top: 5px solid #e74c3c; }
    h2 { color: #e74c3c; margin-top: 0; }
    .badge { display: inline-block; background: #e74c3c; color: white; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: bold; margin-bottom: 20px; }
    table { width: 100%; border-collapse: collapse; margin: 20px 0; }
    td { padding: 10px 14px; border-bottom: 1px solid #eeeeee; vertical-align: top; }
    td:first-child { font-weight: bold; color: #555; width: 180px; white-space: nowrap; }
    .error-box { background: #fff5f5; border-left: 4px solid #e74c3c; padding: 12px 16px; border-radius: 4px; font-size: 14px; white-space: pre-wrap; word-break: break-word; }
    .stack { background: #1e1e2e; color: #cdd6f4; font-family: monospace; font-size: 12px; padding: 16px; border-radius: 6px; overflow-x: auto; white-space: pre-wrap; word-break: break-all; }
    .btn { display: inline-block; background: #3498db; color: white; padding: 10px 20px; border-radius: 5px; text-decoration: none; margin: 5px; font-size: 14px; }
    .footer { margin-top: 30px; font-size: 12px; color: #aaa; text-align: center; }
  </style>
</head>
<body>
  <div class="container">
    <div class="badge">🚨 ERROR ALERT</div>
    <h2>Workflow Execution Failed</h2>
    <table>
      <tr><td>Workflow Name</td><td>${workflowName}</td></tr>
      <tr><td>Workflow ID</td><td>${workflowId}</td></tr>
      <tr><td>Error Type</td><td>${errorName}</td></tr>
      <tr><td>Failed Node</td><td>${lastNode}</td></tr>
      <tr><td>Execution ID</td><td>${executionId}</td></tr>
      <tr><td>Execution Mode</td><td>${executionMode}</td></tr>
      <tr><td>Started At</td><td>${startedAt}</td></tr>
      <tr><td>Alert Time (IST)</td><td>${readableTime}</td></tr>
    </table>

    <h3 style="color:#e74c3c">❌ Full Error Details</h3>
    <div class="error-box">${fullErrorMessage.replace(/\n/g, '<br>')}</div>

    <h3 style="color:#555">📟 Stack Trace</h3>
    <div class="stack">${stackTrace}</div>

    <div style="margin-top:24px">
      <a href="${workflowUrl}" class="btn">🔗 Open Workflow</a>
      <a href="${executionUrl}" class="btn" style="background:#27ae60">📋 View Execution</a>
    </div>
    <div class="footer">Sent by n8n Global Error Handler • ${timestamp}</div>
  </div>
</body>
</html>
`;

// Slack message
const slackMessage = `🚨 *WORKFLOW ERROR ALERT*
━━━━━━━━━━━━━━━━━━━━━━━━

📋 *Workflow Details*
- *Name:* ${workflowName}
- *ID:* ${workflowId}

❌ *Error Info*
- *Type:* ${errorName}
- *Message:* ${errorMessage}${errorCause ? `\n- *Cause:* ${errorCause}` : ''}${httpStatus ? `\n- *HTTP Status:* ${httpStatus}` : ''}${apiResponseBody ? `\n- *API Response:* ${typeof apiResponseBody === 'object' ? JSON.stringify(apiResponseBody) : apiResponseBody}` : ''}

🔍 *Execution Details*
- *Failed Node:* ${lastNode}
- *Execution ID:* ${executionId}
- *Mode:* ${executionMode}
- *Started At:* ${startedAt}
- *Alert Time (IST):* ${readableTime}

🔗 *Quick Actions*
- <${workflowUrl}|👉 Open Workflow>
- <${executionUrl}|📋 View Execution>

━━━━━━━━━━━━━━━━━━━━━━━━`;

return [{
  json: {
    workflowName,
    workflowId,
    workflowUrl,
    executionId,
    executionUrl,
    executionMode,
    startedAt,
    lastNode,
    errorMessage,
    errorName,
    errorCause,
    httpStatus,
    apiResponseBody,
    fullErrorMessage,
    stackTrace,
    timestamp,
    readableTime,
    emailHtml,
    slackMessage,
    emailSubject: `🚨 [n8n ERROR] ${workflowName} — ${errorName}: ${errorMessage}`
  }
}];
